    [114794] = [[Located in The Scullery, Return to Karazhan (Dungeon). The Scullery is adjacent to The Banquet Hall. You don't have to defeat Moroes to reach it.]],
    [114991] = [[Situated in the broken tower in the south-west of the island. In order to see it you must ensure Theramore Isle is set to its pre-destruction phase - if it isn't then speak to Zidormi on the west side of the bridge, west of Theramore. To activate the Arachnodrone you must first obtain an Electrified Key by defeating Doctor Weavil, upstairs in the largest building. The drop-rate of the key isn't 100% so you might have to kill him a few times before you obtain one, but he doesn't take long to respawn. Once activated, the arachnodrone must be reduced to 30% health before it can be tamed. Be ready to interrupt its Maximum Repair spell or it'll heal to full health.]],
    [114992] = [[Found just outside the northern-most building on the island. In order to see it you must ensure Theramore Isle is set to its pre-destruction phase - if it isn't then speak to Zidormi on the west side of the bridge, west of Theramore. To activate the Arachnodrone you must first obtain an Electrified Key by defeating Doctor Weavil, upstairs in the largest building. The drop-rate of the key isn't 100% so you might have to kill him a few times before you obtain one, but he doesn't take long to respawn. Once activated, the arachnodrone must be reduced to 30% health before it can be tamed. Be ready to interrupt its Maximum Repair spell or it'll heal to full health.]],
    [114993] = [[Found in an underground cell that can be reached from a sloping passage just outside the largest building on the island. In order to see it you must ensure Theramore Isle is set to its pre-destruction phase - if it isn't then speak to Zidormi on the west side of the bridge, west of Theramore. To activate the Arachnodrone you must first obtain an Electrified Key by defeating Doctor Weavil, upstairs in the largest building. The drop-rate of the key isn't 100% so you might have to kill him a few times before you obtain one, but he doesn't take long to respawn. Once activated, the arachnodrone must be reduced to 30% health before it can be tamed. Be ready to interrupt its Maximum Repair spell or it'll heal to full health.]],
    [115479] = [[You must reduce Model GU-4RD-3R to 30% health or below in order to tame it. If you're high level this can be difficult to do without killing it, but one way to reduce your damage is to remove all your armour and use your auto shots. Failing that, you can weaken yourself further by getting yourself killed and choosing to take resurrection sickness.]],
    [115671] = [[Only present on days when the world quest Direbeak Swarm! is active.]],
