    [127279] = [[The larger ones are tameable, but the smaller, more active ones (same name, but different ID) are not. Located north of the Primal Wetlands.]],
    [127290] = [['Mugg' is actually intended to be the name of the trogg riding this saurolisk. He dies once it is tamed, but the pet retains the trogg portrait. This is sure to be a bug.]],
