    [143700] = [[Horde hunters can tame this alpaca the usual way, but it is friendly to Alliance and can only be tamed by Alliance hunters using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. It can be found in several locations: (i) at a stable just south-east of Proudmoore Keep; (ii) at a stable by the Boralus Wall, just north of the harbor gates, and (iii) at the stables in Hatherord, to the north of Boralus.]],
    [143718] = [[Found sporadically in coastal areas of Tiragarde, especially outside Boralus, and in north-eastern waters of Stormsong.]],
    [143740] = [[This alpaca is normally friendly to Horde and can only be tamed by using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. The version of Dot with this ID appears at Vulpera Hideaway after completing the main zone quest chain. She doesn't appear to be visible to Alliance.]],
    [143741] = [[This alpaca is normally friendly to Horde and can only be tamed by using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. The version of Dolly with this ID appears at Vulpera Hideaway after completing the main zone quest chain. She doesn't appear to be visible to Alliance.]],
    [144246] = [[Located in The Under Junk, Operation: Mechagon (Dungeon). The sixth boss in the Operation: Mechagon dungeon, K.U.-J.0. is the second boss of the underground section.]],
    [144477] = [[The Mountain Goat with this ID is carried by an Ettin Stoneflinger. The ettin will drop the goat if attacked, or if it decides to attack another NPC (which happens often), and the goat will flee to the west. It's possible to tame the goat before it despawns, but you must be extremely quick. It's best to wait by the path to the west of the ettin and target the goat as soon as the ettin drops it and decides to attacks something else.]],
    [144638] = [[Located in Battle of Dazar'alor (Raid). This undead version of Grong only appears in the Alliance version of the raid, so cannot be tamed by Horde hunters. He's the third boss of the raid.]],
    [144731] = [[Alliance hunters that are able to tame undead will be able to tame this skeletal hound in the usual way, but it is friendly to Horde and can only be tamed by Horde hunters using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. These hounds only appear during Horde assaults on Drustvar. Two can be found on the Horde airship, just north-east of Arom's Stand, in the company of Kaldras Snape. They're located just below decks in the stern of the ship.]],
    [144825] = [[Located in Island Expeditions (Scenario). A possible encounter on Crestfall, Havenswood, Molten Cay, Skittering Hollow, Un'gol Ruins, Verdant Wilds, Whispering Reef.]],
    [144826] = [[Located in Island Expeditions (Scenario). A possible encounter on Molten Cay, Un'gol Ruins, Verdant Wilds.]],
    [144827] = [[Located in Island Expeditions (Scenario). A possible encounter on Havenswood, Molten Cay, Verdant Wilds.]],
