    [145110] = [[Alliance hunters can tame this creature in the usual way, but it is friendly to Horde and can only be tamed by Horde hunters using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. It is present when a Faction Assault is active in Tiragarde Sound, but only when the Alliance quest Not Too Sober Citizens Brigade is offered.]],
    [145337] = [[Found throughout Nazjatar. The bronze colour does not seem to make sounds when clicked.]],
    [145444] = [[Alliance hunters can tame this creature in the usual way, but it is friendly to Horde and can only be tamed by Horde hunters using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. It is present when a Faction Assault is active in Tiragarde Sound, but only when the Alliance quest Not Too Sober Citizens Brigade is offered.]],
    [145457] = [[Alliance hunters can tame this creature in the usual way, but it is friendly to Horde and can only be tamed by Horde hunters using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. It is present when a Faction Assault is active in Tiragarde Sound, but only when the Alliance quest Not Too Sober Citizens Brigade is offered.]],
    [145736] = [[Located in Dunwald Ruins, Twilight Highlands (Vulpera Allied Race Recruitment Phase). This saber is only available during the Vulpera Allied Race recruitment questline which means it's only ever available to Horde hunters, and possibly only once ever on your account. Of interest, this cat was originally mis-classed as a wolf, but that was fixed in the 9.0 pre-expansion patch.]],
    [145740] = [[Normally friendly to both factions, but can be tamed if you use the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. Tinitoa wears a silver crown that is lost upon taming.]],
    [146321] = [[Located in Twilight Vineyards, Suramar (Vulpera Allied Race Recruitment Phase). The version of the Tattered Silkwing with this ID is only available during the Vulpera Allied Race recruitment questline which means it's only ever available to Horde hunters, and possibly only once ever on your account.]],
    [146564] = [[Located in Shrine of the Eclipse, The Sunwell (Scenario). This unique beast first appeared in the Blood Elf Heritage quest chain (blood elf-only), but since Patch 11.2.7 other races can encounter it by running "The Children of Blood" chapter of the "Lorewalking: The Elves of Quel'thalas" campaign, given by Lorewalker Cho in Stormwind, Orgrimmar, and Dornogal. See Wowhead's Lorewalking Overview for more information.]],
    [147453] = [[This alpaca is normally friendly and can only be tamed by using the toy "N'lyeth, Sliver of N'Zoth" while in War Mode. It only appears during Alliance assaults on Vol'dun, and can be found at a Horde camp in the south-west of the zone, far to the south-west of Whistlebloom Oasis and north-west of Scorched Sands Outpost. Look for a zeppelin tethered at some ruins.]],
    [148117] = [[Located in Battle of Dazar'alor (Raid). This version of Grong only appears in the Horde version of the raid, so cannot be tamed by Alliance hunters. He's the second boss of the raid.]],
