    [151096] = [[Located in Spark of the Imagination (Hati quest phase), Ulduar. This version of Hati is the one you initially tame during the Spark of Genius quest chain. He sports the default appearance he had when he was bound to the artifact weapon, Titanstrike, during Legion.]],
    [151133] = [['Titanstrike' : One of the six essences of Hati that may be summoned and tamed at the Shrine of Storms after restoring Hati to life during the Spark of Genius quest chain . The colour of this version is identical to the one you tame in the Spark of Imagination, in the previous stage of the quest chain, which was also the default appearance he had when he was bound to the artifact weapon, Titanstrike, during Legion. There's also a vendor, Clockwerk, in the Temple of Storms who sells toys and consumables to use with Hati.]],
    [151144] = [['Eaglewatch' : One of the six essences of Hati that may be summoned and tamed at the Shrine of Storms after restoring Hati to life during the Spark of Genius quest chain . There's also a vendor, Clockwerk, in the Temple of Storms who sells toys and consumables to use with Hati.]],
    [151145] = [['Elekk's Thunder' : One of the six essences of Hati that may be summoned and tamed at the Shrine of Storms after restoring Hati to life during the Spark of Genius quest chain . There's also a vendor, Clockwerk, in the Temple of Storms who sells toys and consumables to use with Hati.]],
    [151147] = [['Boarshot Cannon' : One of the six essences of Hati that may be summoned and tamed at the Shrine of Storms after restoring Hati to life during the Spark of Genius quest chain . There's also a vendor, Clockwerk, in the Temple of Storms who sells toys and consumables to use with Hati.]],
    [151148] = [['Serpentbite' : One of the six essences of Hati that may be summoned and tamed at the Shrine of Storms after restoring Hati to life during the Spark of Genius quest chain . There's also a vendor, Clockwerk, in the Temple of Storms who sells toys and consumables to use with Hati.]],
    [151149] = [['Hati's Sacrifice' : One of the six essences of Hati that may be summoned and tamed at the Shrine of Storms after restoring Hati to life during the Spark of Genius quest chain . There's also a vendor, Clockwerk, in the Temple of Storms who sells toys and consumables to use with Hati.]],
    [151159] = [[This mechanical rocket chicken only appears on days when Oglethorpe Obnoticus is visiting Rustbolt. It runs rapidly and randomly over most of the island, usually following roads and paths. It runs very quickly so you'll have to be quick to tame or rely on stuns and slows.]],
