    [180678] = [[Found around the northern zone entrance, Keeper's Respite, and the nothern tip of Sanctuary of Guidance.]],
    [180924] = [[Summoning Garudeon requires finding three Energizing Leporids in the general area near Garudeon's nest. After feeding the three hatchlings the Leporids, Garudeon will appear.]],
    [181211] = [[Can be found flying around the tops of mushrooms in the north-eastern section of the House of Plagues.]],
    [181212] = [[Found at limited locations around the Citadel. Two can be found flying by the western edge of the main area and a third can be found sitting on the ground in a plaza further east.]],
    [181213] = [[These non-aggressive mechanical gryphons can be found at at least five locations around the Eternal Forge.]],
    [181359] = [[It loses its Maw-corruption effect upon taming.]],
    [181383] = [[It loses its Maw-corruption effect upon taming.]],
