    [181861] = [[Located in Neltharus (Dungeon).]],
    [182363] = [[The red and bronze variants of this annelid seem to be far rarer than the other two colours (perhaps only a tenth of the frequency).]],
    [183265] = [[There appears to only be one NPC with this ID. It is found on the eastern side of Fissured Breach (at roughly 1 o'clock on the zone's circular road), on a pinnacle of rock off the south side of the road.]],
    [183291] = [[Can be found in at least four locations: One circles around the southeastern area of the zone. Another one flies between the main landmass and the Sepulcher of the First Ones. Another flies between the northern mountains and the center of the zone. Another flies between the center of the zone and the western mountains.]],
    [183610] = [[Found outside the raid entrance.]],
    [183764] = [[Initially, Zatojin cannot be attacked. To activate it, you need to accumulate 20 stacks of Paralytic Sting from the nearby Menacing Vespoid Workers.]],
    [183925] = [[Found atop the high cliffs in northern Fissured Breach. In the absence of flying you will need to unlock teleporter points until you can reach it.]],
    [183984] = [[The cave entrance is around 47.5, 71.9. Follow the cave to the very back, where you'll find a goblin named Boomhooch the Lost. If you speak to Boomhooch and offer to rescue him it will induce the Vilomah to spawn.]],
    [184023] = [[Located in Uldaman: Legacy of Tyr (Dungeon).]],
    [184403] = [[Summoned by Vexis during combat.]],
    [184804] = [[The Unbroken spawns as a trio of worms, each with a different NPC ID, but only the one with this ID is tameable. They can appear in two colours, and if you're unlucky you may have to kill all of them and wait for respawns until your desired colour appears. Their respawn time is only a few minutes.]],
    [185266] = [[Can spawn in various locations around Zereth Mortis.]],
    [185451] = [[Upon reaching you, Gardens Avians with this ID will start to rise into the sky and despawn, so start to tame from a distance! A frost trap does not prevent them despawning.]],
    [185487] = [[Found in the south-east of the zone, on a rise overlooking the main circular road. It will not be up at the same time as Orixal.]],
    [185505] = [[Summoned by Feasting during combat.]],
    [185944] = [[Summoned by Zatojin during combat.]],
    [186399] = [[Spawns during the quest, "Ice Breakers".]],
    [187111] = [[Found in a cave at the northern end of the Wild Coast.]],
    [187246] = [[Located in Azure Vault (Dungeon).]],
    [187336] = [[Loses Time Effect upon taming.]],
