    [189744] = [[The green and white variants make sounds when clicked on, the orange does not.]],
    [190708] = [[Part of the zone story quest, "Connection to Ohn'ahra". Located at the river ford approximately mid-way between Maruukai and Rusza'thar Reach.]],
    [190730] = [[Just west of Three-Falls Lookout. Spawns during the quest, "Water Safety".]],
    [191496] = [[Loses its lightning effect after taming.]],
