    [216039] = [[Located on the west side of the pit, by the city wall. Has a black aura that is retained upon taming.]],
    [216044] = [[Flies rapidly about wilds in the east of the zone, west of Mmarl.]],
    [216078] = [[Dwells in a small cave in the east of the area.]],
    [216197] = [[Only present during the campaign quest chain when the area is under attack, i.e. during 'The Cavalry is Here', etc.]],
    [216249] = [[Has a chance to spawn when you dig up a patch of Disturbed Earth around any of the main Khaz Algar ('The War Within') zones. To unlock this you need to complete the quest Everyday I'm Snufflin in The Ringing Deeps.]],
    [216288] = [[Has a chance to spawn when you dig up a patch of Disturbed Earth around any of the main Khaz Algar ('The War Within') zones. To unlock this you need to complete the quest Everyday I'm Snufflin in The Ringing Deeps.]],
