    [219790] = [[Initially, this magma snail cannot be interacted with or tamed due to it being ridden by a kobold: either a Kobold Trapper (Candleslag Quarry) or a Brightrock Shellvalier (inside the Hallowfall Gate mines). Once the kobold is dead the snail becomes a standalone NPC and can be tamed.]],
    [219949] = [[Found in regions south and east of The Earthenworks and north of Brunwin's Terrace, up to the entrance to the Lost Mines area.]],
    [220059] = [[Found by the pond outside Tenir's Ascent.]],
    [220300] = [[Occasionally found around the hills in the west of the city. It appears to be buggy as even though you can attack it or cast tame, it ignores you and the tame fails, and then it despawns.]],
    [220399] = [[Often found carrying a package on its back that is lost upon taming.]],
    [220483] = [[Often found carrying a container on its back that is lost upon taming.]],
    [220707] = [[Summoned by Battelfront Haulers during combat in Arathi's End in the north-east of the zone. Also summoned by the rare Kaheti Silkhauler during combat. This rare follows the north-south road in the north-east of the zone. Its range extends from Azj-Kahet in the far north-east (east of Faerin's Advance), south past Rak-Zakaz, and probably as far south as the road to the south-west of Rak-Ahat.]],
    [221065] = [[Located in The Three Shields (Quest Phase), Isle of Dorn. Found in a special phase for the Ringing Deeps quest, 'The Wickless Candle'.]],
